import{e as a,f as s,D as m}from"./framework.16919e8f.js";const e='{"title":"Шива сутра","description":"","frontmatter":{"title":"Шива сутра","subtitle":"Ключевое писание Васугупты","sans":"शिवसूत्रा","trans":"śivasūtrā","tags":"text","date":"2021-07-01T00:00:00.000Z"},"headers":[{"level":2,"title":"Часть первая","slug":"часть-первая"},{"level":2,"title":"Часть вторая","slug":"часть-вторая"},{"level":2,"title":"Часть третья","slug":"часть-третья"}],"relativePath":"texts/shiva-sutra/index.md","lastUpdated":1625159513332}',p={},n=m('<h2 id="часть-первая"><a class="header-anchor" href="#часть-первая" aria-hidden="true">#</a> Часть первая</h2><p class="sans">शाम्भवोपाय</p><p class="trans">Śāmbhavopāya</p><p>Метод, основанный на точке зрения Шамбху (Шивы)</p><div class="stanza"><a href="#s1.1" id="s1.1" class="num">1.1</a><p class="sans">चैतन्यमात्मा ॥१॥</p><p class="trans">Caitanyamātmā ॥1॥</p><p>Всезнающее и всемогущее Сознание <em>(caitanyam)</em> [есть] Высшее Я, истинная природа Реальности <em>(ātmā)</em></p></div><div class="stanza"><a href="#s1.2" id="s1.2" class="num">1.2</a><p class="sans">ज्ञानं बन्धः ॥२॥</p><p class="trans">Jñānaṁ bandhaḥ ॥2॥</p><p>[Ограниченное] знание <em>(jñānam)</em> — рабство <em>(bandhaḥ)</em></p></div><div class="stanza"><a href="#s1.3" id="s1.3" class="num">1.3</a><p class="sans">योनिवर्गः कलाशरीरम् ॥३॥</p><p class="trans">Yonivargaḥ kalāśarīram ॥3॥</p><p>Чрево <em>(yoni)</em> <em>(и его)</em> отпрыски <em>(vargaḥ)</em>, [вместе с тем, чья] форма <em>(śarīram)</em> — деятельность <em>(kalā)</em>, [также порабощают].</p></div><div class="stanza"><a href="#s1.4" id="s1.4" class="num">1.4</a><p class="sans">ज्ञानाधिष्ठानं मातृका ॥४॥</p><p class="trans">Jñānādhiṣṭhānaṁ mātṛkā ॥4॥</p><p>Основа <em>(adhiṣṭhānam)</em> [ограниченного] знания <em>(jñāna)</em> — непонятая Мать <em>(mātṛkā)</em></p></div><div class="stanza"><a href="#s1.5" id="s1.5" class="num">1.5</a><p class="sans">उद्यमो भैरवः ॥५॥</p><p class="trans">Udyamo bhairavaḥ ॥5॥</p><p>Бхайрава --Всевышний-- <em>(bhairavaḥ)</em> — [это] внезапная вспышка, или возвышение, божественного Сознания <em>(udyamaḥ)</em></p></div><div class="stanza"><a href="#s1.6" id="s1.6" class="num">1.6</a><p class="sans">शक्तिचक्रसन्धाने विश्वसंहारः ॥६॥</p><p class="trans">Śakticakrasandhāne viśvasaṁhāraḥ ॥6॥</p><p>При единении <em>(sandhāne)</em> с группой <em>(cakra)</em> сил <em>(śakti)</em> <em>(происходит)</em> исчезновение <em>(saṁhāraḥ)</em> вселенной <em>(viśva)</em></p></div><div class="stanza"><a href="#s1.7" id="s1.7" class="num">1.7</a><p class="sans">जाग्रत्स्वप्नसुषुप्तभेदे तुर्याभोगसम्भवः ॥७॥</p><p class="trans">Jāgratsvapnasuṣuptabhede turyābhogasambhavaḥ ॥7॥</p><p>[Даже] во время разных [состояний сознания, таких как] <em>(bhede)</em> бодрствование <em>(jāgrat)</em>, сон <em>(svapna)</em> и глубокий сон <em>(suṣupta)</em>, присутствуют <em>(sambhavaḥ)</em> восторг и наслаждение <em>(ābhoga)</em> Четвёртым Состоянием <em>(turya)</em></p></div><div class="stanza"><a href="#s1.8" id="s1.8" class="num">1.8</a><p class="sans">ज्ञानं जाग्रत् ॥८॥</p><p class="trans">Jñānaṁ jāgrat ॥8॥</p><p>Знание <em>(jñānam)</em> [есть] бодрствование <em>(jāgrat)</em></p></div><div class="stanza"><a href="#s1.9" id="s1.9" class="num">1.9</a><p class="sans">स्वप्नो विकल्पाः ॥९॥</p><p class="trans">Svapno vikalpāḥ ॥9॥</p><p>Сон <em>(svapnaḥ)</em> [состоит из] мыслей и идей <em>(vikalpāḥ)</em></p></div><div class="stanza"><a href="#s1.10" id="s1.10" class="num">1.10</a><p class="sans">अविवेको मायासौषुप्तम् ॥१०॥</p><p class="trans">Aviveko māyāsauṣuptam ॥10॥</p><p>Неразличение, или бессознательность <em>(avivekaḥ)</em>, [является] глубоким сном <em>(sauṣuptam)</em> майи --невежества-- <em>(māyā)</em></p></div><div class="stanza"><a href="#s1.11" id="s1.11" class="num">1.11</a><p class="sans">त्रितयभोक्ता वीरेशः ॥११॥</p><p class="trans">Tritayabhoktā vīreśaḥ ॥11॥</p><p>Тот хозяин <em>(īśaḥ)</em> <em>(своих)</em> чувств <em>(vīra)</em>, кто является наслаждающимся [вышеупомянутым <em>(ābhoga)</em>, божественным восторгом,] <em>(bhoktā)</em> во время триады [бодрствование, сон и глубокий сон] <em>(tritaya)</em></p></div><div class="stanza"><a href="#s1.12" id="s1.12" class="num">1.12</a><p class="sans">विस्मयो योगभूमिकाः ॥१२॥</p><p class="trans">Vismayo yogabhūmikāḥ ॥12॥</p><p>Стадии <em>(bhūmikāḥ)</em> Йоги <em>(yoga)</em> [являют собой] восхитительное чудо <em>(vismayaḥ)</em></p></div><div class="stanza"><a href="#s1.13" id="s1.13" class="num">1.13</a><p class="sans">इच्छाशक्तिरुमा कुमारी ॥१३॥</p><p class="trans">Icchāśaktirumā kumārī ॥13॥</p><p>Сила воли <em>(icchā śaktiḥ)</em> [просветлённого Йога] — «Великолепие Шивы» <em>(umā)</em>, [то есть] Кумари <em>(kumārī)</em></p></div><div class="stanza"><a href="#s1.14" id="s1.14" class="num">1.14</a><p class="sans">दृश्यं शरीरम् ॥१४॥</p><p class="trans">Dṛśyaṁ śarīram ॥14॥</p><p>Все явления [внешние и внутренние] <em>(dṛśyam)</em> — тело <em>(śarīram)</em> [просветлённого Йога]</p></div><div class="stanza"><a href="#s1.15" id="s1.15" class="num">1.15</a><p class="sans">हृदये चित्तसङ्घट्टाद्दृश्यस्वापदर्शनम् ॥१५॥</p><p class="trans">Hṛdaye cittasaṅghaṭṭāddṛśyasvāpadarśanam ॥15॥</p><p>Через единение <em>(saṅghaṭṭāt)</em> ума <em>(citta)</em> в сердце Сознания <em>(hṛdaye)</em>, происходит появление <em>(darśanam)</em> [всех] феноменов [внешних и внутренних] <em>(dṛśya)</em>, [даже] пустоты <em>(svāpa)</em>, [в их истинном виде]</p></div><div class="stanza"><a href="#s1.16" id="s1.16" class="num">1.16</a><p class="sans">शुद्धतत्त्वसन्धानाद्वापशुशक्तिः ॥१६॥</p><p class="trans">Śuddhatattvasandhānādvāpaśuśaktiḥ ॥16॥</p><p>Или же <em>(vā)</em> через единение <em>(sandhānāt)</em> с Чистым <em>(śuddha)</em> Принципом <em>(tattva)</em>, [Йог становится тем, в ком] [сковывающая] сила <em>(śaktiḥ)</em>, [присущая] ограниченному существу <em>(paśu)</em>, отсутствует <em>(a)</em></p></div><div class="stanza"><a href="#s1.17" id="s1.17" class="num">1.17</a><p class="sans">वितर्क आत्मज्ञानम् ॥१७॥</p><p class="trans">Vitarka ātmajñānam ॥17॥</p><p>Твёрдое и непоколебимое осознание <em>(vitarkaḥ)</em> [«Я — Шива», есть] знание <em>(jñānam)</em> Высшего Я <em>(ātma)</em></p></div><div class="stanza"><a href="#s1.18" id="s1.18" class="num">1.18</a><p class="sans">लोकानन्दः समाधिसुखम् ॥१८॥</p><p class="trans">Lokānandaḥ samādhisukham ॥18॥</p><p>Блаженство, [которое Йог ощущает как Воспринимающий] <em>(ānandaḥ)</em> мир, [состоящий из субъектов и объектов] <em>(loka)</em>, — [это его] наслаждение <em>(sukham)</em> в самадхи <em>(samādhi)</em></p></div><div class="stanza"><a href="#s1.19" id="s1.19" class="num">1.19</a><p class="sans">शक्तिसन्धाने शरीरोत्पत्तिः ॥१९॥</p><p class="trans">Śaktisandhāne śarīrotpattiḥ ॥19॥</p><p>При союзе <em>(sandhāne)</em> с Силой [Воли] <em>(śakti)</em>, [происходит] создание <em>(utpattiḥ)</em> тел <em>(śarīra)</em> [согласно желанию Йога]</p></div><div class="stanza"><a href="#s1.20" id="s1.20" class="num">1.20</a><p class="sans">भूतसन्धानभूतपृथक्त्वविश्वसङ्घट्टाः ॥२०॥</p><p class="trans">Bhūtasandhānabhūtapṛthaktvaviśvasaṅghaṭṭāḥ ॥20॥</p><p>[Другие сверхъестественные силы просветлённого Йога состоят из силы] объединения <em>(sandhāna)</em> сущностей <em>(bhūta)</em>, [силы] разделения <em>(pṛthaktva)</em> всех их --сущностей-- <em>(bhūta)</em> [и силы] воссоединения --saṅghaṭṭa-- <em>(saṅghaṭṭāḥ)</em> всего <em>(viśva)</em>, [что было разделено пространством и временем]</p></div><div class="stanza"><a href="#s1.21" id="s1.21" class="num">1.21</a><p class="sans">शुद्धविद्योदयाच्चक्रेशत्वसिद्धिः ॥२१॥</p><p class="trans">Śuddhavidyodayāccakreśatvasiddhiḥ ॥21॥</p><p>При появлении <em>(udayāt)</em> Шуддхавидьи <em>(śuddhavidyā)</em>, [для Йога наступает] полное достижение <em>(siddhiḥ)</em> господства <em>(īśatva)</em> над группой сил <em>(cakra)</em></p></div><div class="stanza"><a href="#s1.22" id="s1.22" class="num">1.22</a><p class="sans">महाह्रदानुसन्धानान्मन्त्रवीर्यानुभवः ॥२२॥</p><p class="trans">Mahāhradānusandhānānmantravīryānubhavaḥ ॥22॥</p><p>Соединяясь <em>(anusandhānāt)</em> с Великим <em>(mahā)</em> Озером <em>(hrada)</em>, <em>(Йог получает)</em> непосредственный опыт <em>(anubhavaḥ)</em> животворящего источника --силы, потенции-- <em>(vīrya)</em> [всех] мантр <em>(mantra)</em></p></div><h2 id="часть-вторая"><a class="header-anchor" href="#часть-вторая" aria-hidden="true">#</a> Часть вторая</h2><p class="sans">शाक्तोपाय</p><p class="trans">Śāktopāya</p><p>Метод, основанный на точке зрения Шакти</p><div class="stanza"><a href="#s2.1" id="s2.1" class="num">2.1</a><p class="sans">चित्तं मन्त्रः ॥१॥</p><p class="trans">Cittaṁ mantraḥ ॥1॥</p><p>Ум <em>(того, кто постоянно размышляет о Высшей Реальности,)</em> <em>(cittam)</em> [есть] Мантра <em>(mantraḥ)</em></p></div><div class="stanza"><a href="#s2.2" id="s2.2" class="num">2.2</a><p class="sans">प्रयत्नः साधकः ॥२॥</p><p class="trans">Prayatnaḥ sādhakaḥ ॥2॥</p><p>[Рьяное и спонтанное] усилие <em>(prayatnaḥ)</em> эффективно для достижения успеха <em>(sādhakaḥ)</em></p></div><div class="stanza"><a href="#s2.3" id="s2.3" class="num">2.3</a><p class="sans">विद्याशरीरसत्ता मन्त्ररहस्यम् ॥३॥</p><p class="trans">Vidyāśarīrasattā mantrarahasyam ॥3॥</p><p>[Сияющая] Сущность [Совершенного Осознания Я] <em>(sattā)</em>, [состоящая из множества слов], чьей сутью <em>(śarīra)</em> [является] знание [высшей недвойственности] <em>(vidyā)</em>, — секрет <em>(rahasyam)</em> Мантры <em>(mantra)</em></p></div><div class="stanza"><a href="#s2.4" id="s2.4" class="num">2.4</a><p class="sans">गर्भे चित्तविकासोऽविशिष्टविद्यास्वप्नः ॥४॥</p><p class="trans">Garbhe cittavikāso&#39;viśiṣṭavidyāsvapnaḥ ॥4॥</p><p>Удовлетворённость <em>(vikāsaḥ)</em> ума <em>(citta)</em> [ограниченными] майическими силами <em>(garbhe)</em> — [всего лишь] сон <em>(svapnaḥ)</em>, [основанный на] низшем <em>(aviśiṣṭa)</em> знании <em>(vidyā)</em></p></div><div class="stanza"><a href="#s2.5" id="s2.5" class="num">2.5</a><p class="sans">विद्यासमुत्थाने स्वाभाविके खेचरी शिवावस्था ॥५॥</p><p class="trans">Vidyāsamutthāne svābhāvike khecarī śivāvasthā ॥5॥</p><p>При спонтанном <em>(svābhāvike)</em> появлении <em>(samutthāne)</em> [Высшего] Знания <em>(vidyā)</em>, в безграничном пространстве Сознания [происходит] движение <em>(khecarī)</em>, [которое называется] состоянием <em>(avasthā)</em> Шивы <em>(śiva)</em></p></div><div class="stanza"><a href="#s2.6" id="s2.6" class="num">2.6</a><p class="sans">गुरुरुपायः ॥६॥</p><p class="trans">Gururupāyaḥ ॥6॥</p><p>Гуру <em>(guruḥ)</em> [является] средством <em>(upāyaḥ)</em></p></div><div class="stanza"><a href="#s2.7" id="s2.7" class="num">2.7</a><p class="sans">मातृकाचक्रसम्बोधः ॥७॥</p><p class="trans">Mātṛkācakrasambodhaḥ ॥7॥</p><p>[От довольного Гуру нисходит] просветление <em>(sambodhaḥ)</em> в отношении группы <em>(cakra)</em> букв <em>(mātṛkā)</em></p></div><div class="stanza"><a href="#s2.8" id="s2.8" class="num">2.8</a><p class="sans">शरीरं हविः ॥८॥</p><p class="trans">Śarīraṁ haviḥ ॥8॥</p><p>Тело [человека, в которое было излито вышеупомянутое просветление,] <em>(śarīram)</em> [превращается в] подношение <em>(haviḥ)</em></p></div><div class="stanza"><a href="#s2.9" id="s2.9" class="num">2.9</a><p class="sans">ज्ञानमन्नम् ॥९॥</p><p class="trans">Jñānamannam ॥9॥</p><p>[Ограниченное] знание <em>(jñānam)</em> [является] пищей <em>(annam)</em></p></div><div class="stanza"><a href="#s2.10" id="s2.10" class="num">2.10</a><p class="sans">विद्यासंहारे तदुत्थस्वप्नदर्शनम् ॥१०॥</p><p class="trans">Vidyāsaṁhāre tadutthasvapnadarśanam ॥10॥</p><p>При исчезновении <em>(saṁhāre)</em> [Чистого] Знания <em>(vidyā)</em> [происходит] появление <em>(darśanam)</em> колебаний ума [как во сне] <em>(svapna)</em>, возникающих <em>(uttha)</em> из-за него <em>(tad)</em> [из-за предшествующего исчезновения Чистого Знания]</p></div><h2 id="часть-третья"><a class="header-anchor" href="#часть-третья" aria-hidden="true">#</a> Часть третья</h2><p class="sans">आणवोपाय</p><p class="trans">Āṇavopāya</p><p>Метод, основанный на точке зрения аṇu, ограниченного существа</p><div class="stanza"><a href="#s3.1" id="s3.1" class="num">3.1</a><p class="sans">आत्मा चित्तम् ॥१॥</p><p class="trans">Ātmā cittam ॥1॥</p><p>Индивидуальное Я <em>(ātmā)</em> [есть] ум <em>(cittam)</em></p></div><div class="stanza"><a href="#s3.2" id="s3.2" class="num">3.2</a><p class="sans">ज्ञानं बन्धः ॥२॥</p><p class="trans">Jñānaṁ bandhaḥ ॥2॥</p><p>[Порождённое умом] знание <em>(jñānam)</em> — рабство <em>(bandhaḥ)</em></p></div><div class="stanza"><a href="#s3.3" id="s3.3" class="num">3.3</a><p class="sans">कलादीनां तत्त्वानामविवेको माया ॥३॥</p><p class="trans">Kalādīnāṁ tattvānāmaviveko māyā ॥3॥</p><p>Неразличение <em>(avivekaḥ)</em> [таких] принципов <em>(tattvānām)</em>, как кала <em>(kalā)</em> и т.д. <em>(ādīnām)</em>, [есть] майя <em>(māyā)</em></p></div><div class="stanza"><a href="#s3.4" id="s3.4" class="num">3.4</a><p class="sans">शरीरे संहारः कलानाम् ॥४॥</p><p class="trans">Śarīre saṁhāraḥ kalānām ॥4॥</p><p>Растворение <em>(saṁhāraḥ)</em> частей <em>(kalānām)</em> --таттв, принципов проявления-- в теле [физическом, тонком и каузальном] <em>(śarīre)</em> [должно выполняться с помощью bhāvanā, творческого созерцания]</p></div><div class="stanza"><a href="#s3.5" id="s3.5" class="num">3.5</a><p class="sans">नाडीसंहारभूतजयभूतकैवल्यभूतपृथक्त्वानि ॥५॥</p><p class="trans">Nāḍīsaṁhārabhūtajayabhūtakaivalyabhūtapṛthaktvāni ॥5॥</p><p>[Йог должен достичь] растворения [жизненной энергии] <em>(saṁhāra)</em> в тонких каналах <em>(nāḍī)</em>, победы <em>(jaya)</em> над грубыми элементами <em>(bhūta)</em>, отозвания [своего ума] <em>(kaivalya)</em> от грубых элементов <em>(bhūta)</em> [и] отделения --pṛthaktva-- <em>(pṛthaktvāni)</em> от грубых элементов <em>(bhūta)</em> [с помощью bhāvanā, творческого созерцания]</p></div><div class="stanza"><a href="#s3.6" id="s3.6" class="num">3.6</a><p class="sans">मोहावरणात्सिद्धिः ॥६॥</p><p class="trans">Mohāvaraṇātsiddhiḥ ॥6॥</p><p>Сверхъестественная сила <em>(siddhiḥ)</em> [появляется] из-за вуали <em>(āvaraṇāt)</em>, [которой покрывает] майя, или невежество <em>(moha)</em></p></div><div class="stanza"><a href="#s3.7" id="s3.7" class="num">3.7</a><p class="sans">मोहजयादनन्ताभोगात्सहजविद्याजयः ॥७॥</p><p class="trans">Mohajayādanantābhogātsahajavidyājayaḥ ॥7॥</p><p>[Йог достигает] овладения <em>(jayaḥ)</em> Естественным <em>(sahaja)</em> Знанием <em>(vidyā)</em> через повсеместную победу <em>(jayāt anantābhogāt)</em> над майей, невежеством <em>(moha)</em></p></div><div class="stanza"><a href="#s3.8" id="s3.8" class="num">3.8</a><p class="sans">जाग्रद्द्वितीयकरः ॥८॥</p><p class="trans">Jāgraddvitīyakaraḥ ॥8॥</p><p>[Йог, достигший Sahajavidyā, Естественного Знания,] бодр и бдителен <em>(jāgrat)</em>, [в то время как] второй [то есть мир] <em>(dvitīya)</em>, [является] в виде [его собственного] сияния <em>(karaḥ)</em></p></div><div class="stanza"><a href="#s3.9" id="s3.9" class="num">3.9</a><p class="sans">नर्तक आत्मा ॥९॥</p><p class="trans">Nartaka ātmā ॥9॥</p><p>[Этот Йог —] Высшее Я <em>(ātmā)</em> [в виде всего лишь] танцующего актёра <em>(nartakaḥ)</em></p></div><div class="stanza"><a href="#s3.10" id="s3.10" class="num">3.10</a><p class="sans">रङ्गोऽन्तरात्मा ॥१०॥</p><p class="trans">Raṅgo&#39;ntarātmā ॥10॥</p><p>Сценой [этому Нартаке, танцующему актёру] <em>(raṅgaḥ)</em> [служит его] внутренняя <em>(antar)</em> душа <em>(ātmā)</em>, [состоящая из каузального и тонкого тел]</p></div><div class="stanza"><a href="#s3.11" id="s3.11" class="num">3.11</a><p class="sans">प्रेक्षकाणीन्द्रियाणि ॥११॥</p><p class="trans">Prekṣakāṇīndriyāṇi ॥11॥</p><p>Чувства [этого Нартаки, танцующего актёра,] <em>(indriyāṇi)</em> [становятся] зрителями [его игры] <em>(prekṣakāṇi)</em></p></div><div class="stanza"><a href="#s3.12" id="s3.12" class="num">3.12</a><p class="sans">धीवशात्सत्त्वसिद्धिः ॥१२॥</p><p class="trans">Dhīvaśātsattvasiddhiḥ ॥12॥</p><p>С помощью <em>(vaśāt)</em> высшего духовного разума <em>(dhī)</em> [происходит] осознание <em>(siddhiḥ)</em> тонкой, мерцающей, внутренней вибрации совершенного Сознания Я <em>(sattva)</em></p></div><div class="stanza"><a href="#s3.13" id="s3.13" class="num">3.13</a><p class="sans">सिद्धः स्वतन्त्रभावः ॥१३॥</p><p class="trans">Siddhaḥ svatantrabhāvaḥ ॥13॥</p><p>Состояние <em>(bhāvaḥ)</em> Независимости и Свободы <em>(svatantra)</em> достигнуто <em>(siddhaḥ)</em></p></div><div class="stanza"><a href="#s3.14" id="s3.14" class="num">3.14</a><p class="sans">यथा तत्र तथान्यत्र ॥१४॥</p><p class="trans">Yathā tatra tathānyatra ॥14॥</p><p>Как <em>(yathā)</em> там <em>(tatra)</em>, так <em>(tathā)</em> и где-либо ещё <em>(anyatra)</em>. [Другими словами, независимый Йог способен продемонстрировать Свободу как в своём собственном теле, так и любом другом месте]</p></div><div class="stanza"><a href="#s3.15" id="s3.15" class="num">3.15</a><p class="sans">बीजावधानम् ॥१५॥</p><p class="trans">Bījāvadhānam ॥15॥</p><p>[Этот Йог должен сфокусировать всё своё] внимание <em>(avadhānam)</em> на Семени [на Высшей Шакти, совершенном Сознании Я, являющимся источником всего проявленного] <em>(bīja)</em></p></div><div class="stanza"><a href="#s3.16" id="s3.16" class="num">3.16</a><p class="sans">आसनस्थः सुखं ह्रदे निमज्जति ॥१६॥</p><p class="trans">Āsanasthaḥ sukhaṁ hrade nimajjati ॥16॥</p><p>Укоренившись <em>(sthaḥ)</em> в силе Высшей Шакти, [в совершенном Сознании Я, служащему ему] сиденьем, <em>(āsana)</em> [просветлённый Йог] с лёгкостью <em>(sukham)</em> погружается <em>(nimajjati)</em> в Озеро [бессмертного божественного Сознания] <em>(hrade)</em></p></div><div class="stanza"><a href="#s3.17" id="s3.17" class="num">3.17</a><p class="sans">स्वमात्रानिर्माणमापादयति ॥१७॥</p><p class="trans">Svamātrānirmāṇamāpādayati ॥17॥</p><p>[Этот освобождённый Йог способен] создать <em>(nirmāṇam āpādayati)</em> [любую форму согласно] мере или аспекту созидательного Сознания, [служащего ему āsana, сиденьем] <em>(svamātrā)</em></p></div><div class="stanza"><a href="#s3.18" id="s3.18" class="num">3.18</a><p class="sans">विद्याविनाशे जन्मविनाशः ॥१८॥</p><p class="trans">Vidyāvināśe janmavināśaḥ ॥18॥</p><p>Покуда Sahajavidyā или Śuddhavidyā [Естественное или Чистое Знание] <em>(vidyā)</em> не исчезает <em>(avināśe)</em>, [возможность нового] рождения <em>(janma)</em> исчезает [для этого возвышенного Йога] <em>(vināśaḥ)</em></p></div><div class="stanza"><a href="#s3.19" id="s3.19" class="num">3.19</a><p class="sans">कवर्गादिषु माहेश्वर्याद्याः पशुमातरः ॥१९॥</p><p class="trans">Kavargādiṣu māheśvaryādyāḥ paśumātaraḥ ॥19॥</p><p>Махешвари <em>(māheśvarī)</em> и другие богини <em>(ādyāḥ)</em>, [чьей сферой влияния является] группа <em>(varga)</em> «ka» <em>(ka)</em> и т.д. <em>(ādiṣu)</em>, матери <em>(mātaraḥ)</em> ограниченных существ <em>(paśu)</em>, [становятся их верховными божествами]</p></div><div class="stanza"><a href="#s3.20" id="s3.20" class="num">3.20</a><p class="sans">त्रिषु चतुर्थं तैलवदासेच्यम् ॥२०॥</p><p class="trans">Triṣu caturthaṁ tailavadāsecyam ॥20॥</p><p>Четвёртое состояние сознания, [которое является Свидетелем] <em>(caturtham)</em>, следует вливать <em>(āsecyam)</em> подобно <em>(vat)</em> [непрерывному потоку] масла <em>(taila)</em> в [остальные] три <em>(triṣu)</em> <em>(бодрствование, сон и глубокий сон)</em></p></div><div class="stanza"><a href="#s3.21" id="s3.21" class="num">3.21</a><p class="sans">मग्नः स्वचित्तेन प्रविशेत् ॥२१॥</p><p class="trans">Magnaḥ svacittena praviśet ॥21॥</p><p>Следует входить [в четвёртое состояние сознания] <em>(praviśet)</em>, погружаясь [в него] <em>(magnaḥ)</em> своим <em>(sva)</em> умом <em>(cittena)</em> [свободным от мыслей]</p></div><div class="stanza"><a href="#s3.22" id="s3.22" class="num">3.22</a><p class="sans">प्राणसमाचारे समदर्शनम् ॥२२॥</p><p class="trans">Prāṇasamācāre samadarśanam ॥22॥</p><p>Когда [происходит] медленное, но устойчивое, распространение <em>(samācāre)</em> жизненной энергии <em>(Йога)</em> <em>(prāṇa)</em>, [наступает] равное <em>(sama)</em> видение <em>(darśanam)</em>, [то есть Йог осознаёт единство всего]</p></div><div class="stanza"><a href="#s3.23" id="s3.23" class="num">3.23</a><p class="sans">मध्येऽवरप्रसवः ॥२३॥</p><p class="trans">Madhye&#39;varaprasavaḥ ॥23॥</p><p>На серединном этапе [не в начале или в конце бодрствования, сна и глубокого сна] <em>(madhye)</em> имеет место быть возникновение <em>(prasavaḥ)</em> низких [состояний ума] <em>(avara)</em></p></div><div class="stanza"><a href="#s3.24" id="s3.24" class="num">3.24</a><p class="sans">मात्रास्वप्रत्ययसन्धाने नष्टस्य पुनरुत्थानम् ॥२४॥</p><p class="trans">Mātrāsvapratyayasandhāne naṣṭasya punarutthānam ॥24॥</p><p>При слиянии <em>(sandhāne)</em> истинного Сознания Я <em>(svapratyaya)</em> с объектами <em>(mātrā)</em>, вновь [возникает] появление <em>(punar utthānam)</em> [Блаженства четвёртого состояния сознания, которое] исчезло <em>(naṣṭasya)</em> [из-за возникновения вышеупомянутых низких состояний ума]</p></div><div class="stanza"><a href="#s3.25" id="s3.25" class="num">3.25</a><p class="sans">शिवतुल्यो जायते ॥२५॥</p><p class="trans">Śivatulyo jāyate ॥25॥</p><p>[Возвышенный Йог, достигший четвёртого состояния сознания,] становится <em>(jāyate)</em> равным <em>(tulyaḥ)</em> Шиве <em>(śiva)</em></p></div><div class="stanza"><a href="#s3.26" id="s3.26" class="num">3.26</a><p class="sans">शरीरवृत्तिर्व्रतम् ॥२६॥</p><p class="trans">Śarīravṛttirvratam ॥26॥</p><p>Пребывание <em>(vṛttiḥ)</em> в теле <em>(śarīra)</em> — [его] обет <em>(vratam)</em>. [Другими словами, он продолжает жить в теле только из-за огромного сострадания к человечеству, как акт благочестия]</p></div><div class="stanza"><a href="#s3.27" id="s3.27" class="num">3.27</a><p class="sans">कथा जपः ॥२७॥</p><p class="trans">Kathā japaḥ ॥27॥</p><p>[Его] речь <em>(kathā)</em> — шептание [мантры или молитвы] <em>(japaḥ)</em></p></div><div class="stanza"><a href="#s3.28" id="s3.28" class="num">3.28</a><p class="sans">दानमात्मज्ञानम् ॥२८॥</p><p class="trans">Dānamātmajñānam ॥28॥</p><p>Знание <em>(jñānam)</em> Высшего Я <em>(ātma)</em> — [его] дар <em>(dānam)</em> [всем нам]</p></div><div class="stanza"><a href="#s3.29" id="s3.29" class="num">3.29</a><p class="sans">योऽविपस्थो ज्ञाहेतुश्च ॥२९॥</p><p class="trans">Yo&#39;vipastho jñāhetuśca ॥29॥</p><p>Тот, кто <em>(yaḥ)</em> укоренён [в группе сил, śakticakra] <em>(avipasthaḥ)</em>, воистину <em>(ca)</em> [является] орудием <em>(hetuḥ)</em> мудрости <em>(jñā)</em></p></div><div class="stanza"><a href="#s3.30" id="s3.30" class="num">3.30</a><p class="sans">स्वशक्तिप्रचयोऽस्य विश्वम् ॥३०॥</p><p class="trans">Svaśaktipracayo&#39;sya viśvam ॥30॥</p><p>Вселенная <em>(viśvam)</em> [является] расширением, разворачиванием, <em>(pracayaḥ)</em> его [Йога] собственной <em>(sva... asya)</em> Силы <em>(śakti)</em></p></div><div class="stanza"><a href="#s3.31" id="s3.31" class="num">3.31</a><p class="sans">स्थितिलयौ ॥३१॥</p><p class="trans">Sthitilayau ॥31॥</p><p>Поддержание [вселенной] <em>(sthiti)</em> [и её] растворение <em>(layau)</em> [также являются разворачиванием его Силы]</p></div><div class="stanza"><a href="#s3.32" id="s3.32" class="num">3.32</a><p class="sans">तत्प्रवृत्तावप्यनिरासः संवेत्तृभावात् ॥३२॥</p><p class="trans">Tatpravṛttāvapyanirāsaḥ saṁvettṛbhāvāt ॥32॥</p><p>Даже <em>(api)</em> когда происходят <em>(pravṛttau)</em> те [три процесса: проявление, поддержание и растворение вселенной] <em>(tad)</em>, [внутреннее состояние великого Йога] не прерывается <em>(anirāsaḥ)</em> в связи с [его] состоянием <em>(bhāvāt)</em> [Высшего] Воспринимающего <em>(saṁvettṛ)</em></p></div><div class="stanza"><a href="#s3.33" id="s3.33" class="num">3.33</a><p class="sans">सुखदुःखयोर्बहिर्मननम् ॥३३॥</p><p class="trans">Sukhaduḥkhayorbahirmananam ॥33॥</p><p>[Этот возвышенный Йог] рассматривает <em>(mananam)</em> наслаждение и боль <em>(sukhaduḥkhayoḥ)</em> как нечто внешнее <em>(bahis)</em></p></div><div class="stanza"><a href="#s3.34" id="s3.34" class="num">3.34</a><p class="sans">तद्विमुक्तस्तु केवली ॥३४॥</p><p class="trans">Tadvimuktastu kevalī ॥34॥</p><p>[Поскольку этот благородный Йог] абсолютно свободен <em>(vimuktaḥ)</em> от того --наслаждения и боли-- <em>(tad)</em>, то <em>(tu)</em> [он] один <em>(kevalī)</em>. [Он пребывает в своём Высшем Я, являющимся единственным Знающим и единственной массой чистого Сознания]</p></div><div class="stanza"><a href="#s3.35" id="s3.35" class="num">3.35</a><p class="sans">मोहप्रतिसंहतस्तु कर्मात्मा ॥३५॥</p><p class="trans">Mohapratisaṁhatastu karmātmā ॥35॥</p><p>Тем не менее <em>(tu)</em>, тот, кто является плотной массой <em>(pratisaṁhataḥ)</em> заблуждения <em>(moha)</em>, [всего лишь] вовлечён <em>(ātmā)</em> в действия <em>(karma)</em></p></div><div class="stanza"><a href="#s3.36" id="s3.36" class="num">3.36</a><p class="sans">भेदतिरस्कारे सर्गान्तरकर्मत्वम् ॥३६॥</p><p class="trans">Bhedatiraskāre sargāntarakarmatvam ॥36॥</p><p>Когда двойственность <em>(bheda)</em> исчезает <em>(tiraskāre)</em>, [у просветлённого Йога появляется] способность реализовать <em>(karmatvam)</em> ещё одно <em>(antara)</em> Творение <em>(sarga)</em></p></div><div class="stanza"><a href="#s3.37" id="s3.37" class="num">3.37</a><p class="sans">करणशक्तिः स्वतोऽनुभवात् ॥३७॥</p><p class="trans">Karaṇaśaktiḥ svato&#39;nubhavāt ॥37॥</p><p>[Любой может убедиться в своей] созидательной <em>(karaṇa)</em> силе <em>(śaktiḥ)</em> на собственном <em>(svataḥ)</em> опыте <em>(anubhavāt)</em></p></div><div class="stanza"><a href="#s3.38" id="s3.38" class="num">3.38</a><p class="sans">त्रिपदाद्यनुप्राणनम् ॥३८॥</p><p class="trans">Tripadādyanuprāṇanam ॥38॥</p><p>[Следует выполнять] оживление <em>(anuprāṇanam)</em> трёх состояний --проявления, поддержания и растворения-- <em>(tri-pada)</em> главным <em>(ādi)</em> [четвёртым состоянием сознания, Свидетелем остальных трёх, полным трансцендентального Блаженства]</p></div><div class="stanza"><a href="#s3.39" id="s3.39" class="num">3.39</a><p class="sans">चित्तस्थितिवच्छरीरकरणबाह्येषु ॥३९॥</p><p class="trans">Cittasthitivaccharīrakaraṇabāhyeṣu ॥39॥</p><p>Как <em>(vat)</em> ментальные <em>(citta)</em> состояния <em>(sthiti)</em>, <em>(так и)</em> тело <em>(śarīra)</em>, органы чувств <em>(karaṇa)</em> и внешние объекты --bāhya-- <em>(bāhyeṣu)</em> [следует оживлять, вливая в них Блаженство четвёртого состояния сознания]</p></div><div class="stanza"><a href="#s3.40" id="s3.40" class="num">3.40</a><p class="sans">अभिलाषाद्बहिर्गतिः संवाह्यस्य ॥४०॥</p><p class="trans">Abhilāṣādbahirgatiḥ saṁvāhyasya ॥40॥</p><p>Из-за желания, порождённого ощущением недостатка <em>(abhilāṣāt)</em>, ограниченное существо <em>(saṁvāhyasya)</em> устремляется наружу <em>(bahirgatiḥ)</em> [и, таким образом, становится жертвой цикла самсары, или трансмиграции от одной формы жизни к другой]</p></div><div class="stanza"><a href="#s3.41" id="s3.41" class="num">3.41</a><p class="sans">तदारूढप्रमितेस्तत्क्षयाज्जीवसङ्क्षयः ॥४१॥</p><p class="trans">Tadārūḍhapramitestatkṣayājjīvasaṅkṣayaḥ ॥41॥</p><p>[Тем не менее,] в случае [великого Йога], чьё сознание <em>(pramiteḥ)</em> укоренилось <em>(ārūḍha)</em> в Том --в четвёртом состоянии, в Турье-- <em>(tad)</em>, при избавлении <em>(kṣayāt)</em> от того [желания] <em>(tad)</em> <em>(также)</em> полностью исчезает <em>(saṅkṣayaḥ)</em> [и состояние] ограниченного существа <em>(jīva)</em></p></div><div class="stanza"><a href="#s3.42" id="s3.42" class="num">3.42</a><p class="sans">भूतकञ्चुकी तदा विमुक्तो भूयः पतिसमः परः ॥४२॥</p><p class="trans">Bhūtakañcukī tadā vimukto bhūyaḥ patisamaḥ paraḥ ॥42॥</p><p>Тогда, [когда желание исчезает] <em>(tadā)</em>, [Йог использует своё тело, состоящее из] грубых элементов <em>(bhūta)</em>, как оболочку <em>(kañcukī)</em> [и, будучи] полностью освобождённым <em>(vimuktaḥ)</em> и в высшей степени <em>(bhūyas)</em> подобным <em>(samaḥ)</em> Господу [Шиве] <em>(pati)</em>, <em>(он)</em> совершенен и полон <em>(paraḥ)</em></p></div><div class="stanza"><a href="#s3.43" id="s3.43" class="num">3.43</a><p class="sans">नैसर्गिकः प्राणसम्बन्धः ॥४३॥</p><p class="trans">Naisargikaḥ prāṇasambandhaḥ ॥43॥</p><p>Связь <em>(sambandhaḥ)</em> жизненной энергии <em>(prāṇa)</em> [с телом] естественна <em>(naisargikaḥ)</em></p></div><div class="stanza"><a href="#s3.44" id="s3.44" class="num">3.44</a><p class="sans">नासिकान्तर्मध्यसंयमात् किमत्र सव्यापसव्यसौषुम्नेषु ॥४४॥</p><p class="trans">Nāsikāntarmadhyasaṁyamāt kimatra savyāpasavyasauṣumneṣu ॥44॥</p><p>[Жизненная энергия --prāṇaśakti, или prāṇa--] [находится] в левом тонком канале --iḍā-- <em>(apasavya)</em>, в правом тонком канале --piṅgalā-- <em>(savya)</em> [и] в suṣumnā --среднем тонком канале-- <em>(sauṣumneṣu)</em>.<br> Посредством непрерывного и интенсивного осознания <em>(saṁyamāt)</em> центра --совершенного Сознания Я-- <em>(madhya)</em> внутреннего аспекта <em>(antar)</em> [вышеупомянутой] prāṇaśakti <em>(nāsikā)</em>, [Йог навсегда укореняется в восприятии высшего и совершенного Сознания Я].</p><p>Что ещё [можно сказать] <em>(kim)</em> об этом <em>(atra)</em>?</p></div><div class="stanza"><a href="#s3.45" id="s3.45" class="num">3.45</a><p class="sans">भूयः स्यात्प्रतिमीलनम् ॥४५॥</p><p class="trans">Bhūyaḥ syātpratimīlanam ॥45॥</p><p>[В случае просветлённого Йога] вновь и вновь <em>(bhūyas)</em> имеет место быть <em>(syāt)</em> осознание Высшего Я, как внутренне, так и внешне <em>(pratimīlanam)</em></p></div>',89);p.render=function(m,e,p,t,i,r){return a(),s("div",null,[n])};export default p;export{e as __pageData};
